// SPDX-License-Identifier: Apache-2.0
// Copyright Authors of Cilium

package policy

import (
	"context"
	"encoding/json"

	"github.com/sirupsen/logrus"

	"github.com/cilium/cilium/pkg/identity"
	"github.com/cilium/cilium/pkg/lock"
	"github.com/cilium/cilium/pkg/logging"
	"github.com/cilium/cilium/pkg/logging/logfields"
)

// PolicyAuditLogger provides structured logging of policy evaluation decisions
// for audit and debugging purposes.
type PolicyAuditLogger struct {
	lock.Mutex

	logger logrus.FieldLogger
	level  logrus.Level
}

// NewPolicyAuditLogger creates a new PolicyAuditLogger with the specified log level.
func NewPolicyAuditLogger(level logrus.Level) *PolicyAuditLogger {
	return &PolicyAuditLogger{
		logger: logging.DefaultLogger,
		level:  level,
	}
}

// NewPolicyAuditLoggerWithLogger creates a new PolicyAuditLogger with the specified
// logger and log level.
func NewPolicyAuditLoggerWithLogger(logger logrus.FieldLogger, level logrus.Level) *PolicyAuditLogger {
	return &PolicyAuditLogger{
		logger: logger,
		level:  level,
	}
}

// LogDecision logs a policy decision with identity, policy information, verdict and reason.
func (pal *PolicyAuditLogger) LogDecision(identity identity.NumericIdentity, policy string, verdict string, reason string) {
	pal.Lock()
	defer pal.Unlock()

	if pal.logger.(*logrus.Entry).Logger.Level < pal.level {
		return
	}

	entry := pal.logger.WithFields(logrus.Fields{
		logfields.Identity: identity,
		"policy":           policy,
		"verdict":          verdict,
		"reason":           reason,
	})

	entry.Log(pal.level, "Policy decision")
}

// PolicyEvaluationResult represents the result of a policy evaluation.
type PolicyEvaluationResult struct {
	PolicyKey string      `json:"policy_key"`
	Verdict   string      `json:"verdict"`
	Reason    string      `json:"reason,omitempty"`
	Details   interface{} `json:"details,omitempty"`
}

// LogEvaluation logs a policy evaluation result with context and selector cache information.
func (pal *PolicyAuditLogger) LogEvaluation(ctx context.Context, policyKey string, selectorCache *SelectorCache, result *PolicyEvaluationResult) {
	pal.Lock()
	defer pal.Unlock()

	if pal.logger.(*logrus.Entry).Logger.Level < pal.level {
		return
	}

	// Marshal the result to JSON for structured audit logging
	resultJSON, err := json.Marshal(result)
	if err != nil {
		resultJSON = []byte("{}")
	}

	entry := pal.logger.WithFields(logrus.Fields{
		logfields.PolicyKey: policyKey,
		"evaluation_result": string(resultJSON),
	})

	// Add context information if available
	if ctx != nil {
		if requestID := ctx.Value("request-id"); requestID != nil {
			entry = entry.WithField("request_id", requestID)
		}
	}

	// Add selector cache information if available
	if selectorCache != nil {
		entry = entry.WithField("selector_cache_id", selectorCache)
	}

	entry.Log(pal.level, "Policy evaluation")
}

